  "children": [
    {
      "name": "RegisterPatient",
      "purpose": "Register a new patient in the system",
      "behavior": "Extract patient details from input, validate uniqueness, store in patients data store, and return success or error",
      "boundary": {
        "in_scope": [
          "patient registration",
          "input validation",
          "data store write"
        ],
        "out_of_scope": [
          "booking appointments",
          "retrieving records",
          "profile updates"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "JSON with registration details (name, contact, etc.)",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "registration_result",
          "description": "JSON with success status, patient ID, and message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "input contains valid registration data",
        "patient does not already exist"
      ],
      "postconditions": [
        "new patient record created in patients data store"
      ],
      "guarantees": [
        "patient ID is unique",
        "registration is atomic"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "BookAppointment",
      "purpose": "Book an appointment for a registered patient",
      "behavior": "Extract patient ID and appointment details from input, verify patient exists, check slot availability, store appointment, and return confirmation",
      "boundary": {
        "in_scope": [
          "appointment booking",
          "patient existence check",
          "slot availability",
          "data store write"
        ],
        "out_of_scope": [
          "patient registration",
          "record retrieval",
          "profile updates"
        ]
      },
