      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "UpdateProfile",
      "purpose": "Update patient profile information",
      "behavior": "Extract patient ID and updated fields from input, verify patient exists, update patients data store, and return confirmation",
      "boundary": {
        "in_scope": [
          "profile update",
          "patient existence check",
          "data store write"
        ],
        "out_of_scope": [
          "registration",
          "booking",
          "record retrieval"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "JSON with patient ID and fields to update",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "update_result",
          "description": "JSON with success status and message",
