      "behavior": "Extract the 'command' field from input JSON and return it along with the rest of the data",
      "boundary": {
        "in_scope": [
          "command extraction",
          "input parsing"
        ],
        "out_of_scope": [
          "executing any command",
          "data store access"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "JSON with command field",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "command",
          "description": "String indicating the operation (register/book/records/update)",
          "consumer": "parent"
        },
        {
          "name": "data",
          "description": "Remaining JSON data for the command",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "input is valid JSON"
      ],
      "postconditions": [
        "command and data are extracted"
      ],
      "guarantees": [
        "command is one of the valid commands"
      ],
      "composition_role": "transform",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "ValidateInput",
      "purpose": "Validate the input JSON structure and required fields",
      "behavior": "Check that input has required fields based on command, return validation result",
      "boundary": {
        "in_scope": [
          "input validation",
          "field presence check"
        ],
        "out_of_scope": [
          "executing commands",
          "data store access"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "JSON with command and data",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "validation_result",
          "description": "Boolean indicating validity and error message if invalid",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "input is parseable"
      ],
      "postconditions": [
        "validation result is returned"
      ],
      "guarantees": [
        "validation is deterministic"
      ],
      "composition_role": "validate",
      "stop_decompose": false,
      "stop_reason": ""
    },
    {
      "name": "FormatResponse",
      "purpose": "Format the output JSON with success, data, and message",
      "behavior": "Take the result from a child operation and wrap it in a standard response format",
      "boundary": {
        "in_scope": [
          "response formatting",
          "error handling"
        ],
        "out_of_scope": [
          "executing commands",
          "data store access"
        ]
      },
      "semantic_inputs": [
        {
          "name": "result",
          "description": "Result from a child operation (success, data, message)",
          "source": "previous child output"
        }
      ],
      "semantic_outputs": [
        {
          "name": "output",
          "description": "JSON with success, data, message",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "result is available"
      ],
      "postconditions": [
        "output is formatted"
      ],
      "guarantees": [
        "output conforms to specification"
      ],
      "composition_role": "aggregate",
      "stop_decompose": false,
      "stop_reason": ""
    }
