      "data": "input data",
      "note": "If command is register"
    },
    {
      "from": "RegisterPatient",
      "to": "parent",
      "data": "registration result",
      "note": "Return result"
    },
    {
      "from": "parent",
      "to": "BookAppointment",
      "data": "input data",
      "note": "If command is book"
    },
    {
      "from": "BookAppointment",
      "to": "parent",
      "data": "booking result",
      "note": "Return result"
    },
    {
      "from": "parent",
      "to": "GetRecords",
      "data": "input data",
      "note": "If command is records"
    },
    {
      "from": "GetRecords",
